const approvalId = String($('naechsten offenen Vorschlag waehlen').first().json.approval_id ?? '').trim();
const rows = $items('Google Sheets - Pruefung lesen').map(i => i.json);
const products = $items('Google Sheets - Produkte lesen').map(i => i.json);

function clean(v) {
  return String(v ?? '').replace(/\n/g, ' ').replace(/\s+/g, ' ').trim();
}

function normalize(v) {
  return clean(v)
    .toLowerCase()
    .replace(/&/g, 'und')
    .replace(/\+/g, 'plus')
    .replace(/\u00e4/g, 'ae')
    .replace(/\u00f6/g, 'oe')
    .replace(/\u00fc/g, 'ue')
    .replace(/\u00df/g, 'ss')
    .replace(/[^a-z0-9]/g, '');
}

function tokens(v) {
  // An Wortgrenzen splitten (NICHT normalize, das Leerzeichen entfernt
  // und mehrere Woerter zu einem Klumpen-Token verklebt).
  const cleaned = clean(v).toLowerCase()
    .replace(/\u00e4/g, 'ae').replace(/\u00f6/g, 'oe').replace(/\u00fc/g, 'ue').replace(/\u00df/g, 'ss');
  const parts = cleaned.split(/[^a-z0-9]+/).filter(Boolean);
  return [...new Set(parts.filter(t => t.length >= 2))];
}

function scoreProduct(product, queryA, queryB) {
  const productText = [
    product.product_key,
    product.internal_product_name,
    product.nayax_product_name,
    product.mdb_code
  ].map(clean).join(' ');

  const pNorm = normalize(productText);
  const q1 = normalize(queryA);
  const q2 = normalize(queryB);

  let score = 0;

  if (q1 && pNorm.includes(q1)) score += 70;
  if (q2 && pNorm.includes(q2)) score += 70;

  const internalNorm = normalize(product.internal_product_name);
  const nayaxNorm = normalize(product.nayax_product_name);

  if (internalNorm && q1.includes(internalNorm)) score += 55;
  if (nayaxNorm && q2.includes(nayaxNorm)) score += 55;

  const queryTokens = [...new Set([...tokens(queryA), ...tokens(queryB)])];
  const productTokens = tokens(productText);
  const overlap = queryTokens.filter(t => productTokens.includes(t));
  score += overlap.length * 12;

  if (clean(product.active).toUpperCase() === 'TRUE' || clean(product.active) === '') score += 5;

  return Math.min(score, 99);
}

function keyFromName(name) {
  const base = clean(name)
    .toUpperCase()
    .replace(/\u00c4/g, 'AE')
    .replace(/\u00d6/g, 'OE')
    .replace(/\u00dc/g, 'UE')
    .replace(/\u1e9e/g, 'SS')
    .replace(/\u00df/g, 'SS')
    .replace(/&/g, 'UND')
    .replace(/\+/g, 'PLUS')
    .replace(/[^A-Z0-9]+/g, '_')
    .replace(/^_+|_+$/g, '');
  return `SKU_${base || 'UNBEKANNT'}`;
}

if (!approvalId) {
  throw new Error('approval_id fehlt.');
}

const source = rows.find(r => clean(r.approval_id) === approvalId);

if (!source) {
  throw new Error('Kein Eintrag in Rechnungseingang_Pruefung gefunden fuer approval_id: ' + approvalId);
}

if (clean(source.processed).toUpperCase() === 'TRUE') {
  throw new Error('Dieser Vorschlag wurde bereits verarbeitet. Keine doppelte Lagercharge angelegt.');
}

const sourceItem = clean(source.source_item || source.raw_item_name);
const nayaxName = clean(source.nayax_product_name || source.recognized_product_name || sourceItem);
const suggestedProductKey = clean(source.suggested_product_key) || keyFromName(nayaxName || sourceItem);
const quantityRaw = clean(source.detected_quantity || source.quantity);
const packSize = Math.max(1, Number(source.detected_pack_size || source.pack_size || 1)) || 1;
const quantityPacks = Number(String(quantityRaw).replace(',', '.')) || 0;
const totalQty = quantityPacks > 0 ? quantityPacks * packSize : 0;
const quantity = totalQty > 0 ? String(totalQty) : quantityRaw;
const invoiceMwst = Number(source.detected_mwst_satz || source.mwst_satz || 0) || 0;
const unitCost = clean(source.detected_unit_cost || source.unit_cost);
const _ucNumPrep = Number(String(unitCost).replace(',', '.'));
const unitCostPerPiece = (packSize > 1 && Number.isFinite(_ucNumPrep) && _ucNumPrep > 0)
  ? (_ucNumPrep / packSize).toFixed(4).replace(/\.?0+$/, '')
  : unitCost;
const mhd = clean(source.detected_mhd || source.mhd_invoice || source.mhd_final);
const storage = clean(source.suggested_storage_location || $('Config - WF3').first().json.default_storage_location || 'Lager');

const allProducts = products
  .filter(p => clean(p.product_key))
  .map(p => ({
    product_key: clean(p.product_key),
    internal_product_name: clean(p.internal_product_name),
    nayax_product_name: clean(p.nayax_product_name),
    mdb_code: clean(p.mdb_code),
    sale_price_eur: clean(p.sale_price_eur),
    active: clean(p.active),
    notes: clean(p.notes),
    produktart: clean(p.produktart)
  }));

const MIN_SCORE = 12;
const ranked = products
  .map(p => ({ product: p, score: scoreProduct(p, sourceItem, nayaxName) }))
  .filter(x => clean(x.product.product_key) && x.score >= MIN_SCORE)
  .sort((a, b) => b.score - a.score)
  .slice(0, 3);

const candidates = ranked.map((x, idx) => {
  const p = x.product;
  return {
    number: String(idx + 1),
    product_key: clean(p.product_key),
    internal_product_name: clean(p.internal_product_name),
    nayax_product_name: clean(p.nayax_product_name),
    mdb_code: clean(p.mdb_code),
    sale_price_eur: clean(p.sale_price_eur),
    produktart: clean(p.produktart),
    score: x.score
  };
});

const candidateText = candidates.length
  ? candidates.map(c =>
      `${c.number} = ${c.product_key} | ${c.internal_product_name || c.nayax_product_name || '(ohne Name)'} | Nayax: ${c.nayax_product_name || '(leer)'} | Treffer: ${c.score}%`
    ).join('\n')
  : 'Kein passendes vorhandenes Produkt gefunden (kein Namens-Treffer).\n>> Waehle NEW, um dieses Produkt neu anzulegen.\n(KEY nur, wenn du den exakten product_key eines vorhandenen Produkts kennst.)';

const formInfo = [
  `PRODUKTVORSCHLAEGE:`,
  candidateText,
  ``,
  `AUSWAHL:`,
  `1, 2 oder 3 = einen vorgeschlagenen vorhandenen Produktdatensatz ?bernehmen`,
  `KEY = anderes vorhandenes Produkt per product_key angeben`,
  `NEW = neues Produkt anlegen`,
  `REJECT = Vorschlag ablehnen`,
  ``,
  `RECHNUNGSPOSITION:`,
  `${sourceItem}`,
  ``,
  `Erkannter Nayax-Vorschlag aus Rechnung: ${nayaxName}`,
  `Menge: ${quantityPacks > 0 ? quantityPacks + ' Packungen' : quantityRaw} ? ${packSize} Stueck = ${totalQty || quantity} Einzeleinheiten`,
  `MwSt laut Rechnung: ${invoiceMwst > 0 ? invoiceMwst + '%' : '(nicht erkannt, faellt auf Produktart zurueck)'}`,
  `Einzelkosten (Pack): ${unitCost} EUR  ?  pro Stueck: ${packSize > 1 && Number(String(unitCost).replace(',', '.')) > 0 ? (Number(String(unitCost).replace(',', '.')) / packSize).toFixed(4).replace(/\.?0+$/, '') : unitCost} EUR`,
  `MHD: ${mhd || '(leer)'}`,
  `Lagerort: ${storage}`,
  ``,
  `approval_id: ${approvalId}`,
  ``,
  `Hinweis:`,
  `Bei 1, 2 oder 3 wird der Nayax-Name aus dem vorhandenen Produkt ?bernommen.`,
  `Das Feld new_nayax_product_name ist nur f?r NEW relevant.`
].join('\n');

// Phase A3: MwSt-Satz aus Produktart des besten Kandidaten ableiten
function mwstVonProduktart(art) {
  const a = clean(art).toLowerCase();
  if (a === 'snack' || a.includes('snack') || a === 'riegel') return 7;
  if (a === 'getraenk' || a.includes('getraenk') || a.includes('drink')) return 19;
  return 19; // sicherer Standard
}
const defaultMwstSatz = invoiceMwst > 0 ? invoiceMwst : mwstVonProduktart(candidates[0]?.produktart || '');

return [{
  json: {
    approval_id: approvalId,
    source,
    candidates,
    all_products: allProducts,
    form_info: formInfo,
    default_alias_name: sourceItem,
    default_new_nayax_product_name: nayaxName,
    default_manual_existing_product_key: '',
    default_quantity: quantity,
    default_pack_size: packSize,
    default_total_qty: totalQty,
    default_invoice_mwst_satz: invoiceMwst,
    default_unit_cost: unitCost,
    default_unit_cost_per_piece: unitCostPerPiece,
    default_mhd: mhd,
    default_mwst_satz: defaultMwstSatz,
    default_storage_location: storage,
    suggested_product_key: suggestedProductKey
  }
}];

const prepared = $('Code - Produktvorschlaege vorbereiten').first().json;
const formDecision = $('Form - Produktentscheidung').first().json;
const currentInput = $input.first().json;

function clean(v) {
  return String(v ?? '').replace(/\n/g, ' ').replace(/\s+/g, ' ').trim();
}

function normalize(v) {
  return clean(v)
    .toLowerCase()
    .replace(/&/g, 'und')
    .replace(/\+/g, 'plus')
    .replace(/\u00e4/g, 'ae')
    .replace(/\u00f6/g, 'oe')
    .replace(/\u00fc/g, 'ue')
    .replace(/\u00df/g, 'ss')
    .replace(/[^a-z0-9]/g, '');
}

function first(...vals) {
  return vals.map(clean).find(v => v !== '') || '';
}

function keyFromName(name) {
  const base = clean(name)
    .toUpperCase()
    .replace(/\u00c4/g, 'AE')
    .replace(/\u00d6/g, 'OE')
    .replace(/\u00dc/g, 'UE')
    .replace(/\u1e9e/g, 'SS')
    .replace(/\u00df/g, 'SS')
    .replace(/&/g, 'UND')
    .replace(/\+/g, 'PLUS')
    .replace(/[^A-Z0-9]+/g, '_')
    .replace(/^_+|_+$/g, '');
  return `SKU_${base || 'UNBEKANNT'}`;
}

const choice = clean(formDecision.Auswahl).toUpperCase();

if (!['1', '2', '3', 'KEY', 'NEW', 'REJECT'].includes(choice)) {
  throw new Error('Ungueltige Auswahl. Erlaubt sind 1, 2, 3, KEY, NEW oder REJECT.');
}

const source = prepared.source;
const now = new Date().toISOString();

if (choice === 'REJECT') {
  return [{
    json: {
      approval_id: prepared.approval_id,
      decision: 'reject',
      rejected: true,
      processed_at: now,
      status: 'rejected',
      notes: clean(formDecision.notes || source.notes),

      source_file: clean(source.source_file_name || source.source_file),
      source_file_id: clean(source.source_file_id),
      source_file_name: clean(source.source_file_name),

      invoice_number: clean(source.invoice_number || source.invoice_id),
      invoice_date: clean(source.invoice_date || source.purchase_date),
      invoice_id: clean(source.invoice_id),
      invoice_key: clean(source.invoice_key),

      supplier: clean(source.supplier),
      purchase_date: clean(source.purchase_date),
      line_number: clean(source.line_number),
      source_item: clean(source.source_item),
      raw_item_name: clean(source.source_item || source.raw_item_name),

      recognized_product_name: clean(source.recognized_product_name || source.nayax_product_name),
      suggested_product_key: clean(source.suggested_product_key),
      matched_product_key: clean(source.matched_product_key),

      quantity: clean(source.detected_quantity || source.quantity),
      unit_cost: clean(source.detected_unit_cost || source.unit_cost),
      mhd_invoice: clean(source.detected_mhd || source.mhd_invoice),
      mhd_final: clean(source.mhd_final),

      confidence: 'abgelehnt_manuell',
      mdb_code: clean(source.mdb_code),
      nayax_product_name: clean(source.nayax_product_name),

      existing_product_key: clean(source.existing_product_key),
      existing_product_name: clean(source.existing_product_name),

      suggested_batch_id: clean(source.suggested_batch_id),
      suggested_storage_location: clean(source.suggested_storage_location),
      suggested_action: clean(source.suggested_action),

      needs_user_input: clean(source.needs_user_input),
      missing_fields: clean(source.missing_fields),

      detected_quantity: clean(source.detected_quantity),
      detected_mhd: clean(source.detected_mhd),
      detected_unit_cost: clean(source.detected_unit_cost),

      final_product_key: '',
      final_product_name: '',
      final_mdb_code: '',
      final_sale_price_eur: '',
      final_quantity: '',
      final_mhd: '',
      final_unit_cost: '',
      final_storage_location: '',
      error_message: ''
    }
  }];
}

let selectedProduct = null;
let decision = '';

if (['1', '2', '3'].includes(choice)) {
  const candidate = prepared.candidates.find(c => c.number === choice);

  if (!candidate) {
    throw new Error('Kandidat nicht gefunden fuer Auswahl: ' + choice);
  }

  selectedProduct = {
    product_key: clean(candidate.product_key),
    internal_product_name: clean(candidate.internal_product_name),
    nayax_product_name: clean(candidate.nayax_product_name),
    mdb_code: clean(candidate.mdb_code),
    sale_price_eur: clean(candidate.sale_price_eur)
  };

  decision = 'use_existing_product';
}

if (choice === 'KEY') {
  const manualKey = clean(formDecision.manual_existing_product_key);

  if (!manualKey) {
    throw new Error('Bitte manual_existing_product_key angeben, wenn KEY gewaehlt wurde.');
  }

  const found = prepared.all_products.find(p => clean(p.product_key) === manualKey);

  if (!found) {
    throw new Error('Kein vorhandenes Produkt mit diesem product_key gefunden: ' + manualKey);
  }

  selectedProduct = {
    product_key: clean(found.product_key),
    internal_product_name: clean(found.internal_product_name),
    nayax_product_name: clean(found.nayax_product_name),
    mdb_code: clean(found.mdb_code),
    sale_price_eur: clean(found.sale_price_eur)
  };

  decision = 'use_existing_product_manual_key';
}

if (choice === 'NEW') {
  const newName = first(
    currentInput.new_nayax_product_name,
    prepared.default_new_nayax_product_name,
    source.nayax_product_name,
    source.source_item
  );

  if (!newName) {
    throw new Error('Nayax-Produktname fuer NEW fehlt.');
  }

  selectedProduct = {
    product_key: keyFromName(newName),
    internal_product_name: newName,
    nayax_product_name: newName,
    mdb_code: clean(currentInput.mdb_code_new_optional || formDecision.mdb_code_new_optional),
    sale_price_eur: clean(currentInput.sale_price_eur_new_optional || formDecision.sale_price_eur_new_optional)
  };

  decision = 'create_new_product';
}

const quantityRaw = first(formDecision.quantity_override, prepared.default_quantity);
const quantity = Number(String(quantityRaw).replace(',', '.'));

if (!Number.isFinite(quantity) || quantity <= 0) {
  throw new Error('Menge fehlt oder ist ungueltig: ' + quantityRaw);
}

const purchaseDate = first(source.purchase_date, source.invoice_date, new Date().toISOString().slice(0, 10));
const ymd = purchaseDate.replace(/-/g, '');
const safeProduct = selectedProduct.product_key.replace(/^SKU_/, '').replace(/[^A-Za-z0-9_]/g, '_');
const stableId = prepared.approval_id.replace(/[^A-Za-z0-9]/g, '_');

const aliasName = first(formDecision.alias_name, prepared.default_alias_name, source.source_item);
// Stueckkosten: unit_cost_override ist der FINALE Preis pro Einzeleinheit
// und wird 1:1 gespeichert (kein Teilen). Nur der Rechnungs-Fallback
// (Packpreis) wird durch die Packungsgroesse geteilt.
const _packSizeForCost = Math.max(1, Number(prepared.default_pack_size || source.detected_pack_size || 1)) || 1;
const _overrideRaw = clean(formDecision.unit_cost_override);
const _overrideNum = Number(String(_overrideRaw).replace(',', '.'));
let unitCost;
if (_overrideRaw !== '' && Number.isFinite(_overrideNum) && _overrideNum > 0) {
  unitCost = _overrideNum.toFixed(4).replace(/\.?0+$/, '');
} else {
  const _fallbackRaw = first(prepared.default_unit_cost, source.detected_unit_cost);
  const _fallbackNum = Number(String(_fallbackRaw).replace(',', '.'));
  const _perPiece = (_packSizeForCost > 1 && Number.isFinite(_fallbackNum) && _fallbackNum > 0)
    ? _fallbackNum / _packSizeForCost
    : _fallbackNum;
  unitCost = Number.isFinite(_perPiece) && _perPiece > 0
    ? _perPiece.toFixed(4).replace(/\.?0+$/, '')
    : (_fallbackRaw || '');
}
const mhd = first(formDecision.mhd_override, prepared.default_mhd, source.detected_mhd);
const storageLocation = first(formDecision.storage_location_override, prepared.default_storage_location, 'Lager');
const notes = clean(formDecision.notes || source.notes);

// Phase A3: MwSt-Satz aus Formular oder Produktart ableiten
function mwstVonProduktart(art) {
  const a = String(art ?? '').toLowerCase().trim();
  if (a === 'snack' || a.includes('snack') || a === 'riegel') return 7;
  if (a === 'getraenk' || a.includes('getraenk') || a.includes('drink')) return 19;
  return 19;
}
const invoiceMwst = Number(prepared.default_invoice_mwst_satz || source.detected_mwst_satz || 0) || 0;
const mwstFormRaw = Number(String(formDecision.mwst_satz || '').replace(',', '.'));
const mwstFallback = invoiceMwst > 0
  ? invoiceMwst
  : (selectedProduct
    ? mwstVonProduktart(
        (prepared.all_products || []).find(p => p.product_key === (selectedProduct?.product_key || ''))?.produktart || ''
      )
    : Number(prepared.default_mwst_satz || 19));
const mwstSatz = Number.isFinite(mwstFormRaw) && mwstFormRaw > 0 ? mwstFormRaw : mwstFallback;

return [{
  json: {
    approval_id: prepared.approval_id,
    decision,
    rejected: false,
    selected_choice: choice,

    product_key: selectedProduct.product_key,
    product_name: selectedProduct.internal_product_name || selectedProduct.nayax_product_name,
    internal_product_name: selectedProduct.internal_product_name,
    nayax_product_name: selectedProduct.nayax_product_name,
    mdb_code: selectedProduct.mdb_code,
    sale_price_eur: selectedProduct.sale_price_eur,

    alias_name: aliasName,
    normalized_alias: normalize(aliasName),

    batch_id: `B_${safeProduct}_${ymd}_${stableId}`,
    purchase_date: purchaseDate,
    mhd,
    initial_qty: quantity,
    remaining_qty: quantity,
    quantity,
    unit_cost: (unitCost === '' ? '' : Number(unitCost)),
    supplier: clean(source.supplier),
    storage_location: storageLocation,
    mwst_satz: mwstSatz,
    status: 'aktiv',
    notes,

    source_invoice: first(source.invoice_id, source.invoice_number, source.invoice_key),
    source_item: first(source.source_item, source.raw_item_name),
    confidence: choice === 'NEW'
      ? 'neu_manuell_bestaetigt'
      : 'bestehendes_produkt_manuell_bestaetigt',

    processed_at: now,
    is_new_product: choice === 'NEW',
    start_wf4_assignment: ['ja','yes','true','1'].includes(normalize(formDecision.product_direct_slot_assignment || '')),
    slot_machine_id: first(formDecision.slot_machine_id, '457107528'),
    slot_mdb_code: first(formDecision.slot_mdb_code, selectedProduct.mdb_code),
    slot_current_machine_qty: first(formDecision.slot_current_machine_qty),
    slot_machine_capacity: first(formDecision.slot_machine_capacity),
    slot_target_stock: first(formDecision.slot_target_stock),
    slot_min_stock: first(formDecision.slot_min_stock)
  }
}];

const rows = $input.all().map(i => i.json);

function clean(v) {
  return String(v ?? '').trim();
}

function isTrue(v) {
  return clean(v).toUpperCase() === 'TRUE' || v === true;
}

const openRows = rows.filter(r =>
  clean(r.approval_id) &&
  !isTrue(r.processed)
);

if (!openRows.length) {
  throw new Error('Keine offenen Rechnungsvorschl?ge gefunden.');
}

openRows.sort((a, b) => {
  const da = clean(a.created_at);
  const db = clean(b.created_at);
  return da.localeCompare(db);
});

return [{
  json: {
    approval_id: clean(openRows[0].approval_id)
  }
}];

const row = $input.first().json;
const finalData = $('Code - Entscheidung auswerten').item.json;

if (!row || !row.approval_id) {
  throw new Error('Pruefzeile nicht gefunden: ' + finalData.approval_id);
}

const processed = String(row.processed ?? '').trim().toUpperCase();

if (processed === 'TRUE' || row.processed === true) {
  throw new Error('Dieser Vorschlag wurde bereits verarbeitet. Alias und Lagercharge werden nicht erneut angelegt.');
}

return [{ json: finalData }];

function clean(v){return String(v ?? '').replace(/\n/g,' ').replace(/\s+/g,' ').trim();}
const data = $('Code - Entscheidung auswerten').item.json;
if(!data.start_wf4_assignment) return [];
if(!clean(data.slot_mdb_code)) throw new Error('WF4-Start gew?nscht, aber slot_mdb_code fehlt.');

return [{json:{
  source:'WF2_Rechnungseingang',
  detected_reason:'NEW_PRODUCT_READY_FOR_SLOT_ASSIGNMENT',
  machine_id:clean(data.slot_machine_id || '457107528'),
  product_key:clean(data.product_key),
  suggested_product_key:clean(data.product_key),
  nayax_product_name:clean(data.nayax_product_name || data.product_name),
  product_label:clean(data.nayax_product_name || data.product_name),
  actual_mdb_code:clean(data.slot_mdb_code),
  new_mdb_code:clean(data.slot_mdb_code),
  suggested_change_type:'Produkt im Slot austauschen',
  current_machine_qty:clean(data.slot_current_machine_qty),
  machine_capacity:clean(data.slot_machine_capacity),
  target_stock:clean(data.slot_target_stock),
  min_stock:clean(data.slot_min_stock),
  settlement_datetime_gmt:clean(data.processed_at),
  notes:'Aus WF2 nach Produkt-/Lagerfreigabe zur Slotzuordnung gestartet.'
}}];

// Erzeugt product (optional), product_alias, stock_batch Events fuer WF-PGW
// Input: Items von 'Google Sheets - Lagercharge anlegen'
// Referenz: 'Code - Entscheidung auswerten' fuer Produktdaten

const item = $('Code - Entscheidung auswerten').item.json;
const batchRunId = 'wf2_' + new Date().toISOString().slice(0, 10);

function toInvoiceKey(id) {
  return 'INV_' + String(id || 'UNKNOWN')
    .toUpperCase()
    .replace(/[^A-Z0-9]+/g, '_')
    .replace(/^_+|_+$/g, '');
}

// Kategorie automatisch ableiten (getraenk|snack). Spiegelt
// dashboard/lib/product-category.js (test-validiert gegen alle realen Produkte).
// Konservativ: Default 'snack', nur bei klarem Getraenke-Signal 'getraenk'.
function inferProductCategory() {
  var names = Array.prototype.slice.call(arguments);
  var SUBS = ['fanta','sprite','spezi','mezzo mix','mezzomix','pepsi','capri','red bull','redbull','monster energy','rockstar','effect energy','lichtenauer','gerolsteiner','adelholzener','bionade','paulaner','eiskaffee','eiscafe','eiskaffe','eis kaffee','milchmisch','limonade','mineralwasser','energydrink','energy drink','eistee','ice tea','icetea','eis tee','smoothie','apfelschorle','orangensaft','multivitamin','durstloescher'];
  var WORDS = ['cola','limo','schorle','saft','nektar','tee','kaffee','wasser','energy','drink','getraenk','bull','vio','bier','radler','sprudel'];
  var VOL = [/\b\d{2,4}\s?ml\b/, /\b\d{1,2}[.,]\d{1,2}\s?l\b/, /\b\d{1,2}\s?l\b/, /\bliter\b/];
  function norm(v){ return String(v==null?'':v).toLowerCase().replace(/ä/g,'ae').replace(/ö/g,'oe').replace(/ü/g,'ue').replace(/ß/g,'ss').replace(/[^a-z0-9.,\s]+/g,' ').replace(/\s+/g,' ').trim(); }
  var text = names.map(norm).filter(Boolean).join(' ');
  if (!text) return 'snack';
  for (var i=0;i<SUBS.length;i++){ if (text.indexOf(SUBS[i])!==-1) return 'getraenk'; }
  for (var j=0;j<WORDS.length;j++){ if (new RegExp('\\b'+WORDS[j]+'\\b').test(text)) return 'getraenk'; }
  for (var k=0;k<VOL.length;k++){ if (VOL[k].test(text)) return 'getraenk'; }
  return 'snack';
}

